            }
            Expression::ComputedMemberExpression(member_expr) => {
                if let Some(changed) = Self::substitute_single_use_symbol_in_expression(
                    &mut member_expr.object,
                    search_for,
                    replacement,
                    replacement_has_side_effect,
                    ctx,
                ) {
                    return Some(changed);
