/// Collects all [`ReferenceId`]s from an expression tree.
/// Used to quickly check whether a symbol could possibly be referenced
/// in an expression, avoiding expensive recursive tree walks.
struct ReferenceIdCollector {
    reference_ids: FxHashSet<ReferenceId>,
}

impl ReferenceIdCollector {
    fn from_expression<'a>(expr: &Expression<'a>) -> FxHashSet<ReferenceId> {
        let mut collector = Self { reference_ids: FxHashSet::default() };
        collector.visit_expression(expr);
        collector.reference_ids
    }
}

impl<'a> Visit<'a> for ReferenceIdCollector {
    fn visit_identifier_reference(&mut self, it: &IdentifierReference<'a>) {
        if let Some(reference_id) = it.reference_id.get() {
            self.reference_ids.insert(reference_id);
        }
    }
}

