/// Returns new length
fn substitute_single_use_symbol_in_expression_from_declarators(
    target_expr: &mut Expression<'a>,
    declarators: &mut [VariableDeclarator<'a>],
    ctx: &TraverseCtx<'a>,
    non_scoped_literal_only: bool,
) -> usize {
    // Collect all ReferenceIds from target_expr upfront so we can quickly
    // check whether a symbol could possibly be referenced in the expression.
    // This avoids O(N * M) recursive tree walks when there are many declarators.
    // Only worth the allocation overhead when there are enough declarators
    // to make the quadratic cost significant (e.g. bundled output with
    // thousands of `var` declarations).
    let mut cached_ref_ids: Option<FxHashSet<ReferenceId>> = if declarators.len() >= 64 {
        Some(ReferenceIdCollector::from_expression(target_expr))
    } else {
        None
    };

    let last_non_inlined_index = declarators.iter_mut().rposition(|prev_decl| {
        let Some(prev_decl_init) = &mut prev_decl.init else {
            return true;
        };
        let BindingPattern::BindingIdentifier(prev_decl_id) = &prev_decl.id else {
            return true;
        };
        if ctx.is_expression_whose_name_needs_to_be_kept(prev_decl_init) {
            return true;
        }
        let symbol_id = prev_decl_id.symbol_id();
        let Some(symbol_value) = ctx.state.symbol_values.get_symbol_value(symbol_id) else {
            return true;
        };
        // we should check whether it's exported by `symbol_value.exported`
        // because the variable might be exported with `export { foo }` rather than `export var foo`
        if symbol_value.exported
            || symbol_value.read_references_count > 1
            || symbol_value.write_references_count > 0
        {
            return true;
        }
        if non_scoped_literal_only && !prev_decl_init.is_literal_value(false, ctx) {
            return true;
        }
        // Fast path: if we have a cached set of reference IDs, check whether
        // this symbol's resolved references appear in target_expr at all.
        if let Some(ref_ids) = &cached_ref_ids {
            let has_reference = ctx
                .scoping()
                .get_resolved_reference_ids(symbol_id)
                .iter()
                .any(|ref_id| ref_ids.contains(ref_id));
            if !has_reference {
                return true;
            }
        }
        let replaced = Self::substitute_single_use_symbol_in_expression(
            target_expr,
            &prev_decl_id.name,
            prev_decl_init,
            prev_decl_init.may_have_side_effects(ctx),
            ctx,
        );
        if replaced != Some(true) {
            return true;
        }
        // Invalidate the cache since target_expr was mutated by the substitution.
        cached_ref_ids = None;
        false
    });
    match last_non_inlined_index {
        None => 0,
        Some(last_non_inlined_index) => last_non_inlined_index + 1,
    }
}

