 9937→func (p *parser) visitSingleStmt(stmt js_ast.Stmt, kind stmtsKind) js_ast.Stmt {
 9938→	// To reduce stack depth, special-case blocks and process their children directly
 9939→	if block, ok := stmt.Data.(*js_ast.SBlock); ok {
 9940→		p.pushScopeForVisitPass(js_ast.ScopeBlock, stmt.Loc)
 9941→		block.Stmts = p.visitStmts(block.Stmts, kind)
 9942→		p.popScope()
 9943→		if p.options.minifySyntax {
 9944→			stmt = stmtsToSingleStmt(stmt.Loc, block.Stmts, block.CloseBraceLoc)
 9945→		}
 9946→		return stmt
 9947→	}
 9948→
 9949→	// Introduce a fake block scope for function declarations inside if statements
 9950→	fn, ok := stmt.Data.(*js_ast.SFunction)
 9951→	hasIfScope := ok && fn.Fn.HasIfScope
 9952→	if hasIfScope {
 9953→		p.pushScopeForVisitPass(js_ast.ScopeBlock, stmt.Loc)
 9954→		if p.isStrictMode() {
 9955→			p.markStrictModeFeature(ifElseFunctionStmt, js_lexer.RangeOfIdentifier(p.source, stmt.Loc), "")
 9956→		}
 9957→	}
 9958→
 9959→	p.singleStmtDepth++
 9960→	stmts := p.visitStmts([]js_ast.Stmt{stmt}, kind)
 9961→	p.singleStmtDepth--
 9962→
 9963→	// Balance the fake block scope introduced above
 9964→	if hasIfScope {
 9965→		p.popScope()
 9966→	}
 9967→
 9968→	return stmtsToSingleStmt(stmt.Loc, stmts, logger.Loc{})
 9969→}
