 9971→// One statement could potentially expand to several statements
 9972→func stmtsToSingleStmt(loc logger.Loc, stmts []js_ast.Stmt, closeBraceLoc logger.Loc) js_ast.Stmt {
 9973→	if len(stmts) == 0 {
 9974→		return js_ast.Stmt{Loc: loc, Data: js_ast.SEmptyShared}
 9975→	}
 9976→	if len(stmts) == 1 && !stmtCaresAboutScope(stmts[0]) {
 9977→		return stmts[0]
 9978→	}
 9979→	return js_ast.Stmt{Loc: loc, Data: &js_ast.SBlock{Stmts: stmts, CloseBraceLoc: closeBraceLoc}}
 9980→}
