 9982→func (p *parser) visitForLoopInit(stmt js_ast.Stmt, isInOrOf bool) js_ast.Stmt {
 9983→	switch s := stmt.Data.(type) {
 9984→	case *js_ast.SExpr:
 9985→		assignTarget := js_ast.AssignTargetNone
 9986→		if isInOrOf {
 9987→			assignTarget = js_ast.AssignTargetReplace
 9988→		}
