 9994→			d := &s.Decls[i]
 9995→			p.visitBinding(d.Binding, bindingOpts{})
 9996→			if d.ValueOrNil.Data != nil {
 9997→				d.ValueOrNil = p.visitExpr(d.ValueOrNil)
