10031→			if firstRange := opts.duplicateArgCheck[name]; firstRange.Len > 0 {
10032→				p.log.AddErrorWithNotes(&p.tracker, r,
10033→					fmt.Sprintf("%q cannot be bound multiple times in the same parameter list", name),
