10048→					p.nameToKeepIsFor = item.DefaultValueOrNil.Data
10049→				}
10050→
10051→				item.DefaultValueOrNil = p.visitExpr(item.DefaultValueOrNil)
10052→			}
10053→		}
10054→
10055→	case *js_ast.BObject:
10056→		for i, property := range b.Properties {
10057→			if !property.IsSpread {
10058→				property.Key, _ = p.visitExprInOut(property.Key, exprIn{
10059→					shouldMangleStringsAsProps: true,
10060→				})
10061→			}
10062→			p.visitBinding(property.Value, opts)
10063→			if property.DefaultValueOrNil.Data != nil {
10064→				// Propagate the name to keep from the binding into the initializer
10065→				if id, ok := property.Value.Data.(*js_ast.BIdentifier); ok {
10066→					p.nameToKeep = p.symbols[id.Ref.InnerIndex].OriginalName
10067→					p.nameToKeepIsFor = property.DefaultValueOrNil.Data
10068→				}
10069→
10070→				property.DefaultValueOrNil = p.visitExpr(property.DefaultValueOrNil)
10071→			}
10072→			b.Properties[i] = property
10073→		}
10074→
10075→	default:
