10080→func stmtCaresAboutScope(stmt js_ast.Stmt) bool {
10081→	switch s := stmt.Data.(type) {
10082→	case *js_ast.SBlock, *js_ast.SEmpty, *js_ast.SDebugger, *js_ast.SExpr, *js_ast.SIf,
10083→		*js_ast.SFor, *js_ast.SForIn, *js_ast.SForOf, *js_ast.SDoWhile, *js_ast.SWhile,
10084→		*js_ast.SWith, *js_ast.STry, *js_ast.SSwitch, *js_ast.SReturn, *js_ast.SThrow,
10085→		*js_ast.SBreak, *js_ast.SContinue, *js_ast.SDirective, *js_ast.SLabel:
10086→		return false
10087→
10088→	case *js_ast.SLocal:
10089→		return s.Kind != js_ast.LocalVar
10090→
10091→	default:
10092→		return true
10093→	}
10094→}
