10096→func stmtsCareAboutScope(stmts []js_ast.Stmt) bool {
10097→	for _, stmt := range stmts {
10098→		if stmtCaresAboutScope(stmt) {
10099→			return true
10100→		}
10101→	}
10102→	return false
10103→}
